#include <bits/stdc++.h>
using namespace std;

int n, a[1005];
int f[1005];

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            f[i] = max(f[i], a[j] + f[i - j]);
        }
    }
    cout << f[n];
    return 0;
}
